<?php
namespace App\Domain\Shops;
use InvalidArgumentException;
final class ShopSalePricingService{const BASIS_POINTS_MAX=10000;public function calculate($sellPrice,$rateBasisPoints,$quantity){$this->positiveInteger($sellPrice,'sell price');$this->positiveInteger($rateBasisPoints,'purchase rate');$this->positiveInteger($quantity,'quantity');if($rateBasisPoints>self::BASIS_POINTS_MAX)throw new InvalidArgumentException('Purchase rate must be between 1 and 10000 basis points.');$quotient=intdiv($sellPrice,self::BASIS_POINTS_MAX);$remainder=$sellPrice%self::BASIS_POINTS_MAX;if($quotient>intdiv(PHP_INT_MAX,$rateBasisPoints))throw new InvalidArgumentException('Shop sale unit price exceeds the supported integer range.');$whole=$quotient*$rateBasisPoints;$fraction=intdiv($remainder*$rateBasisPoints,self::BASIS_POINTS_MAX);if($whole>PHP_INT_MAX-$fraction)throw new InvalidArgumentException('Shop sale unit price exceeds the supported integer range.');$unit=$whole+$fraction;if($unit<1)throw new InvalidArgumentException('Shop sale unit price must be at least one gold.');if($quantity>intdiv(PHP_INT_MAX,$unit))throw new InvalidArgumentException('Shop sale total exceeds the supported integer range.');return new ShopSalePriceResult($unit,$quantity,$unit*$quantity);}private function positiveInteger($value,$name){if(!is_int($value)||$value<1)throw new InvalidArgumentException(ucfirst($name).' must be a positive integer.');}}
